public EventExecutionError MoveCard(MoveCardIn param)
{
    ActorRef<Card> card = param.Card;
    AccurateCardPosition destPosition = param.DestPosition;

    if (destPosition.CardPositionType == CardPositionTypes.Null)
    {
        throw new Exception("Cannot move to null position after spawn");
    }

    EventExecutionError error = CanMoveCard(param);
    if (!error)
    {
        return error;
    }

    Card cardObject = GetActorObject(card);
    AccurateCardPosition oriPosition = GetCardPosition(card);

    // Leave old position
    LeaveOldPosition(oriPosition, card);

    // Enter new position
    EnterNewPosition(destPosition, cardObject, card);

    CardPosition cardPosition = (CardPosition)destPosition;
    cardObject.SetCardPosition(cardPosition);

    return true;
}

