            EnterCardDeck(destPosition.PlayerPosition, cardRef, destPosition.AccurateCardDeckPosition);
            break;
        case CardPositionTypes.GraveDeck:
            EnterGraveDeck(destPosition.PlayerPosition, cardRef, destPosition.AccurateGraveDeckPosition);
            break;
        case CardPositionTypes.HandCardDeck:
            EnterHandCardDeck(destPosition.PlayerPosition, cardRef, destPosition.AccurateHandCardPosition);
